starterCode.css:
body {
  display: grid;
  place-items: center;
  min-height: 100vh;
  background: #eef2f7;
  font-family: system-ui, sans-serif;
}

.card {
  /* Hazlo contexto de posicionamiento */
  width: 280px;
  padding: 22px;
  background: white;
  border-radius: 12px;
  box-shadow: 0 6px 20px rgba(0,0,0,0.08);
}

.badge {
  /* Posiciona la etiqueta */
  background: #e76f51;
  color: white;
  padding: 4px 10px;
  border-radius: 999px;
  font-size: 0.8rem;
  font-weight: 700;
}
